<template>
  <div>
    <table
      width="98%"
      border="0"
      align="center"
      cellpadding="0"
      cellspacing="0"
      @click="executeGoToScanPager()"
    >
      <tr>
        <td bgcolor="#0A7E81">
          <table width="100%" border="0" cellpadding="0" cellspacing="0">
            <tr>
              <td width="26%" height="60" align="right">
                <img :src="requireImg('images/file.png')" width="40" height="52" />
              </td>
              <td width="74%"><span class="STYLE1">　我要扫描</span></td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
    <br />
    <br />
    <table
      width="98%"
      border="0"
      align="center"
      cellpadding="0"
      cellspacing="0"
    >
      <tr>
        <td align="center">
          <label>
            <textarea
              name="textarea"
              cols="45"
              rows="5"
              class="bkz"
              id="textarea"
            ></textarea>
          </label>
        </td>
      </tr>
      <tr>
        <td>&nbsp;</td>
      </tr>
      <tr>
        <td>
          <table
            width="100"
            border="0"
            align="right"
            cellpadding="0"
            cellspacing="0"
            @click="executeClear()"
          >
            <tr>
              <td height="50" align="center" bgcolor="#0A7E81" class="STYLE3">
                清除结果
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>

    <div id="list"></div>
    <br />
  </div>
</template>

<script>
export default {
  name: "scan", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //清除扫描结果
    executeClear() {
      document.getElementById("textarea").value = "";
      document.getElementById("list").innerHTML = "";
    },

    //到扫描界面
    executeGoToScanPager() {
      console.log("executeGoToScanPager()-->start");
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }
      //获取平台信息[需要把这边获取的平台信息发送到服务器]
      var devicePlatform = device.platform;

      document.getElementById("list").innerHTML = "";
      //执行到这边表示cordova环境准备完成,在二维码扫描界面
      mam.navigator.forward.goToScanTwoDiemCode(successCallback, errorCallback);

      //执行成功回调
      //这边参数表示扫描成功后返回的字符串
      function successCallback(msg) {
        console.log("successCallback() msg:" + msg);
        //alert("11");
        document.getElementById("textarea").value = msg;
      }

      //执行失败回调[扫描失败，暂不退出界面未做处理]
      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
        document.getElementById("list").innerHTML = "";
      }
    },
     requireImg(url) {
      return require("@/assets/" + url);
    },
  },
};
</script>
<style lang='css' scoped>
/* @import url(); 引入css类 */
</style>